+TEST_F(SourceFilePathSeparatorTest, FunctionSourceFileNonEmptyAndRelative)
+{
+    std::string src = R"(
+        function main() {
+            return 0;
+        }
+    )";
+    std::string realPath = CreateTempFile("src/module/Test.ets", src);
+
+    const char *args[] = {ES2PANDA_BIN_PATH, "--ets-unnamed"};
+    auto program = GetProgram(ark::Span<const char *const>(args, 2), realPath.c_str(), src);
+    ASSERT_NE(program, nullptr);
+
+    // sourceFile must be non-empty, relative, and without backslashes or trailing '/'.
+    // When the file is not under rootDir, it gracefully falls back to just the filename.
+    for (const auto &[funcName, func] : program->functionStaticTable) {
+        if (!IsUserDefined(funcName)) {
+            continue;
+        }
+        ASSERT_FALSE(func.sourceFile.empty()) << "Function '" << funcName << "' has empty sourceFile";
+        EXPECT_NE(func.sourceFile.front(), '/')
+            << "Function '" << funcName << "' sourceFile is absolute: '" << func.sourceFile << "'";
+        EXPECT_NE(func.sourceFile.back(), '/') << "Function '" << funcName << "' sourceFile ends with '/'";
+        EXPECT_TRUE(HasOnlyForwardSlashes(func.sourceFile))
+            << "Function '" << funcName << "' sourceFile contains backslashes: '" << func.sourceFile << "'";
+    }
+}
+
+TEST_F(SourceFilePathSeparatorTest, RecordSourceFileNonEmptyAndRelative)
+{
+    std::string src = R"(
+        class MyClass {
+            myMethod(): void {}
