+
+    const char *args[] = {ES2PANDA_BIN_PATH, "--ets-unnamed"};
+    auto program = GetProgram(ark::Span<const char *const>(args, 2), realPath.c_str(), src);
+    ASSERT_NE(program, nullptr);
+
+    for (const auto &[recordName, record] : program->recordTable) {
+        if (!IsUserDefined(recordName)) {
+            continue;
+        }
+        ASSERT_FALSE(record.sourceFile.empty()) << "Record '" << recordName << "' has empty sourceFile";
+        EXPECT_NE(record.sourceFile.front(), '/')
+            << "Record '" << recordName << "' sourceFile is absolute: '" << record.sourceFile << "'";
+        EXPECT_NE(record.sourceFile.back(), '/') << "Record '" << recordName << "' sourceFile ends with '/'";
+    }
