+std::string Helpers::RelPathByStrippingPrefix(const std::string &absPath, const std::string &prefix)
+{
+    if (prefix.empty() || !StartsWith(absPath, prefix) ||
+        (absPath.size() > prefix.size() && absPath[prefix.size()] != '/')) {
+        return "";
+    }
+    auto relPath = absPath.substr(prefix.size());
+    if (!relPath.empty() && relPath.front() == '/') {
+        relPath = relPath.substr(1);
+    }
+    if (!relPath.empty() && relPath.back() == '/') {
+        relPath.pop_back();
+    }
+    return relPath;
+}
