#include <gtest/gtest.h>
#include "test/utils/asm_test.h"

#include <filesystem>

namespace test::unit {

static bool IsUserDefined(std::string_view name)
{
    return name.find("std.") == std::string_view::npos && name.find("std:") == std::string_view::npos;
}

class SourceFilePathSeparatorTest : public test::utils::AsmTest {
protected:
    bool HasOnlyForwardSlashes(const std::string &path)
    {
        return path.find('\\') == std::string::npos;
    }

    void CheckAllFunctionsSourceFile(const std::unique_ptr<ark::pandasm::Program> &program)
    {
        for (const auto &[funcName, func] : program->functionInstanceTable) {
            EXPECT_TRUE(HasOnlyForwardSlashes(func.sourceFile))
                << "Instance function '" << funcName << "' has sourceFile: '" << func.sourceFile
                << "' which contains backslashes";
        }

        for (const auto &[funcName, func] : program->functionStaticTable) {
            EXPECT_TRUE(HasOnlyForwardSlashes(func.sourceFile))
                << "Static function '" << funcName << "' has sourceFile: '" << func.sourceFile
                << "' which contains backslashes";
        }
    }

    std::string CreateTempFile(std::string_view relativePath, std::string_view content)
    {
        auto filePath = std::filesystem::path(testing::TempDir()) / "sourcefile_test" / relativePath;
        std::filesystem::create_directories(filePath.parent_path());
        std::ofstream ofs(filePath);
        ofs << content;
        ofs.close();
        return filePath.string();
    }
};

TEST_F(SourceFilePathSeparatorTest, CheckFunctionSourceFilePathSeparatorsWithBackslash)
{
    std::string src = R"(
        function main() {
            return 0;
        }
    )";

    const char *args[] = {ES2PANDA_BIN_PATH, "--ets-unnamed"};
    auto program = GetProgram(ark::Span<const char *const>(args, 2), "path\\to\\test.ets", src);
    ASSERT_NE(program, nullptr);

    CheckAllFunctionsSourceFile(program);
}

TEST_F(SourceFilePathSeparatorTest, CheckClassRecordSourceFilePathSeparatorsWithBackslash)
{
    std::string src = R"(
        class MyClass {
            myMethod(): void {
            }
        }
    )";

    const char *args[] = {ES2PANDA_BIN_PATH, "--ets-unnamed"};
    auto program = GetProgram(ark::Span<const char *const>(args, 2), "src\\classes\\MyClass.ets", src);
    ASSERT_NE(program, nullptr);

    for (const auto &[recordName, record] : program->recordTable) {
        EXPECT_TRUE(HasOnlyForwardSlashes(record.sourceFile))
            << "Record '" << recordName << "' has sourceFile: '" << record.sourceFile << "' which contains backslashes";
    }

    CheckAllFunctionsSourceFile(program);
}

TEST_F(SourceFilePathSeparatorTest, CheckInterfaceRecordSourceFilePathSeparatorsWithBackslash)
{
    std::string src = R"(
        interface MyInterface {
            myMethod(): void;
        }
    )";

    const char *args[] = {ES2PANDA_BIN_PATH, "--ets-unnamed"};
    auto program = GetProgram(ark::Span<const char *const>(args, 2), "src\\interfaces\\MyInterface.ets", src);
    ASSERT_NE(program, nullptr);

    for (const auto &[recordName, record] : program->recordTable) {
        EXPECT_TRUE(HasOnlyForwardSlashes(record.sourceFile))
            << "Record '" << recordName << "' has sourceFile: '" << record.sourceFile << "' which contains backslashes";
    }

    CheckAllFunctionsSourceFile(program);
}

TEST_F(SourceFilePathSeparatorTest, CheckAnnotationRecordSourceFilePathSeparatorsWithBackslash)
{
    std::string src = R"(
        @interface MyAnnotation {
        }
    )";

    const char *args[] = {ES2PANDA_BIN_PATH, "--ets-unnamed"};
    auto program = GetProgram(ark::Span<const char *const>(args, 2), "src\\annotations\\MyAnnotation.ets", src);
    ASSERT_NE(program, nullptr);

    for (const auto &[recordName, record] : program->recordTable) {
        EXPECT_TRUE(HasOnlyForwardSlashes(record.sourceFile))
            << "Record '" << recordName << "' has sourceFile: '" << record.sourceFile << "' which contains backslashes";
    }

    CheckAllFunctionsSourceFile(program);
}

TEST_F(SourceFilePathSeparatorTest, FunctionSourceFileNonEmptyAndRelative)
{
    std::string src = R"(
        function main() {
            return 0;
        }
    )";
    std::string realPath = CreateTempFile("src/module/Test.ets", src);

    const char *args[] = {ES2PANDA_BIN_PATH, "--ets-unnamed"};
    auto program = GetProgram(ark::Span<const char *const>(args, 2), realPath.c_str(), src);
    ASSERT_NE(program, nullptr);

    // sourceFile must be non-empty, relative, and without backslashes or trailing '/'.
    // When the file is not under rootDir, it gracefully falls back to just the filename.
    for (const auto &[funcName, func] : program->functionStaticTable) {
        if (!IsUserDefined(funcName)) {
            continue;
        }
        ASSERT_FALSE(func.sourceFile.empty()) << "Function '" << funcName << "' has empty sourceFile";
        EXPECT_NE(func.sourceFile.front(), '/')
            << "Function '" << funcName << "' sourceFile is absolute: '" << func.sourceFile << "'";
        EXPECT_NE(func.sourceFile.back(), '/') << "Function '" << funcName << "' sourceFile ends with '/'";
        EXPECT_TRUE(HasOnlyForwardSlashes(func.sourceFile))
            << "Function '" << funcName << "' sourceFile contains backslashes: '" << func.sourceFile << "'";
    }
}

TEST_F(SourceFilePathSeparatorTest, RecordSourceFileNonEmptyAndRelative)
{
    std::string src = R"(
        class MyClass {
            myMethod(): void {}
        }
    )";
    std::string realPath = CreateTempFile("src/classes/MyClass.ets", src);

    const char *args[] = {ES2PANDA_BIN_PATH, "--ets-unnamed"};
    auto program = GetProgram(ark::Span<const char *const>(args, 2), realPath.c_str(), src);
    ASSERT_NE(program, nullptr);

    for (const auto &[recordName, record] : program->recordTable) {
        if (!IsUserDefined(recordName)) {
            continue;
        }
        ASSERT_FALSE(record.sourceFile.empty()) << "Record '" << recordName << "' has empty sourceFile";
        EXPECT_NE(record.sourceFile.front(), '/')
            << "Record '" << recordName << "' sourceFile is absolute: '" << record.sourceFile << "'";
        EXPECT_NE(record.sourceFile.back(), '/') << "Record '" << recordName << "' sourceFile ends with '/'";
    }
}

TEST_F(SourceFilePathSeparatorTest, FunctionSourceFileNotEndsWithSlash)
{
    std::string src = R"(
        function main() {
            return 0;
        }
    )";
    std::string realPath = CreateTempFile("src/module/Test.ets", src);

    const char *args[] = {ES2PANDA_BIN_PATH, "--ets-unnamed"};
    auto program = GetProgram(ark::Span<const char *const>(args, 2), realPath.c_str(), src);
    ASSERT_NE(program, nullptr);

    for (const auto &[funcName, func] : program->functionStaticTable) {
        if (!IsUserDefined(funcName)) {
            continue;
        }
        ASSERT_FALSE(func.sourceFile.empty());
        EXPECT_NE(func.sourceFile.back(), '/')
            << "Function '" << funcName << "' sourceFile ends with '/': '" << func.sourceFile << "'";
    }
    for (const auto &[recordName, record] : program->recordTable) {
        if (!IsUserDefined(recordName)) {
            continue;
        }
        ASSERT_FALSE(record.sourceFile.empty());
        EXPECT_NE(record.sourceFile.back(), '/')
            << "Record '" << recordName << "' sourceFile ends with '/': '" << record.sourceFile << "'";
    }
}

TEST_F(SourceFilePathSeparatorTest, FunctionSourceFileFallbackWhenFileNotOnDisk)
{
    const char *nonExistentPath = "nonexistent/dir/Test.ets";

    std::string src = R"(
        function main() {
            return 0;
        }
    )";

    const char *args[] = {ES2PANDA_BIN_PATH, "--ets-unnamed"};
    auto program = GetProgram(ark::Span<const char *const>(args, 2), nonExistentPath, src);
    ASSERT_NE(program, nullptr);

    for (const auto &[funcName, func] : program->functionStaticTable) {
        if (!IsUserDefined(funcName)) {
            continue;
        }
        EXPECT_FALSE(func.sourceFile.empty())
            << "Function '" << funcName << "' has empty sourceFile when file not on disk";
    }
}

}  // namespace test::unit

